FROM jsonb_to_recordset('[{"id": "cap-112-society-015", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "圖(七)為跨太平洋夥伴全面\n進步協定(CPTPP)的11個成\n員國。該協定於2018年12月\n30日生效，各成員國之間將                             8\n階段性的廢除關稅，以促進                 1\n貿易往來。此協定生效後，           2\n5              9\n下列何者最可能因關稅劣勢\n4                           10\n而受到衝擊？                   6", "options": ["臺灣的紡織品出口至越南                 7", "加拿大的小麥出口至日本   &3733ノ⎟◉ (C)墨西哥的汽車出口至智利                     圖(七)", "", "馬來西亞的石油出口至印度"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 15, "raw_text": "15. 圖(七)為跨太平洋夥伴全面\n    進步協定(CPTPP)的11個成\n    員國。該協定於2018年12月\n    30日生效，各成員國之間將                             8\n\n    階段性的廢除關稅，以促進                 1\n    貿易往來。此協定生效後，           2\n                               5              9\n    下列何者最可能因關稅劣勢\n                      4                           10\n    而受到衝擊？                   6\n    (A)臺灣的紡織品出口至越南                 7\n    (B)加拿大的小麥出口至日本   &3733ノ⎟◉\n    (C)墨西哥的汽車出口至智利                     圖(七)\n    (D)馬來西亞的石油出口至印度\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-016", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "某地區於2017年入選為世界遺產，該地區涵蓋了森林、谷地、潟湖及珊瑚礁\n等景觀，遺產的中心是玻里尼西亞普遍可見的毛利集會中心，此遺產是毛利\n文化極具代表性的見證。根據上文描述判斷，該遺產最可能位於下列何處？\n(A) (11.88°N，2.49°E)\n(B) (49.93°N，115.43°E)\n(C) (16.84°S，151.37°W)\n(D) (42.85°S，71.87°W)", "options": ["", "", "", ""], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 16, "raw_text": "16. 某地區於2017年入選為世界遺產，該地區涵蓋了森林、谷地、潟湖及珊瑚礁\n    等景觀，遺產的中心是玻里尼西亞普遍可見的毛利集會中心，此遺產是毛利\n    文化極具代表性的見證。根據上文描述判斷，該遺產最可能位於下列何處？\n    (A) (11.88°N，2.49°E)\n    (B) (49.93°N，115.43°E)\n    (C) (16.84°S，151.37°W)\n    (D) (42.85°S，71.87°W)\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-017", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "《周成過臺灣》是著名的民間傳說，其時代背景符合史實。故事描述周成拋\n下故鄉泉州的妻兒，獨自來臺經商。適逢淡水、雞籠開港通商，周成在大稻\n埕從事新興商品出口而致富。後來周成移情別戀，謀殺了來臺灣探視的妻\n子，最終受到報應而死。根據上述內容，周成最有可能從事下列何種商品的\n貿易？", "options": ["茶葉", "鹿皮", "蔗糖", "鴉片"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 17, "raw_text": "17. 《周成過臺灣》是著名的民間傳說，其時代背景符合史實。故事描述周成拋\n    下故鄉泉州的妻兒，獨自來臺經商。適逢淡水、雞籠開港通商，周成在大稻\n    埕從事新興商品出口而致富。後來周成移情別戀，謀殺了來臺灣探視的妻\n    子，最終受到報應而死。根據上述內容，周成最有可能從事下列何種商品的\n    貿易？\n    (A)茶葉          (B)鹿皮\n    (C)蔗糖          (D)鴉片\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-018", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "以下是某歷史人物在其著作中的相關內容：「我們可以假設人類在社會形成\n以前，所有人都是平等的。然而人們為了解決集體生活所產生的問題，透過\n公眾的協商形成公意，且將全部的權力，託付由公意組成的政府，因為能夠\n代表公意的政府，是不受私念限制、必然公正的。政府依循公意制定法律、\n建立秩序，人們只要守法、服從公意，就能得到真正的自由。」上述內容最\n可能與下列何者有關？", "options": ["盧梭關於主權在民的主張", "希特勒針對種族主義的論述", "馬克思對於工廠制度的批評", "孟德斯鳩闡明三權分立的觀點"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 18, "raw_text": "18. 以下是某歷史人物在其著作中的相關內容：「我們可以假設人類在社會形成\n    以前，所有人都是平等的。然而人們為了解決集體生活所產生的問題，透過\n    公眾的協商形成公意，且將全部的權力，託付由公意組成的政府，因為能夠\n    代表公意的政府，是不受私念限制、必然公正的。政府依循公意制定法律、\n    建立秩序，人們只要守法、服從公意，就能得到真正的自由。」上述內容最\n    可能與下列何者有關？\n    (A)盧梭關於主權在民的主張  (B)希特勒針對種族主義的論述\n    (C)馬克思對於工廠制度的批評 (D)孟德斯鳩闡明三權分立的觀點\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-019", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "圖(八)是霞喀羅國家步道的介紹圖，其舊名為「霞喀羅、薩克亞金警備道路」。\n此道路的開闢，是因為過去臺灣統治者為達到某一目的而下令修築。根據圖中\n內容判斷，統治者最初開闢這條道路的目的，最可能與下列何者有關？\n娤⪝⩖⋍梎◦ヾ弸岟            ą 䔺䊼㽬傸Ʊ悋㤝㢋攡◮弸岟\ną ㄼ⃮䳻䘡ⵚ⫆审⫾䏝䏠䕂怐䎴\n㨣弑悊䣉\n\u0013NP                                          \u0015\u0015NP\n\u0014\u000f\u001a\u0015\n\u0015\u000f\u0013\u0017\u0016    \u0014\u000f\u0019\u0017\u0018         \u0014\u000f\u0018\u0013\u0013\n烋ㆪ唝‥㐶⨕㽸㰵㆒榖ⵤ濕⑬ḋ㽸‪⫸Ʋ\n圖(八)", "options": ["劃界封山的施行", "新式製糖的推動", "海運港口的整建", "理蕃政策的實施"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 19, "raw_text": "19. 圖(八)是霞喀羅國家步道的介紹圖，其舊名為「霞喀羅、薩克亞金警備道路」。\n    此道路的開闢，是因為過去臺灣統治者為達到某一目的而下令修築。根據圖中\n    內容判斷，統治者最初開闢這條道路的目的，最可能與下列何者有關？\n\n     娤⪝⩖⋍梎◦ヾ弸岟            ą 䔺䊼㽬傸Ʊ悋㤝㢋攡◮弸岟\n                          ą ㄼ⃮䳻䘡ⵚ⫆审⫾䏝䏠䕂怐䎴\n\n\n                                                   㨣弑悊䣉\n    \u0013NP                                          \u0015\u0015NP\n          \u0014\u000f\u001a\u0015\n   \u0015\u000f\u0013\u0017\u0016    \u0014\u000f\u0019\u0017\u0018         \u0014\u000f\u0018\u0013\u0013\n                                   烋ㆪ唝‥㐶⨕㽸㰵㆒榖ⵤ濕⑬ḋ㽸‪⫸Ʋ\n                          圖(八)\n  (A)劃界封山的施行               (B)新式製糖的推動\n  (C)海運港口的整建               (D)理蕃政策的實施\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-020", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "「關於我的『政治主張』，因為和蔣委員長在意見上的衝突，已經沒有和解的\n跡象。我考慮了三種方法來解決此事，第一是辭職、第二是勸諫、第三是兵\n諫。第一個方法因為我的國難家仇，和東北軍部下們的反對而不可行。最近我\n試了第二個方法，但導致蔣委員長極端憤怒。因此我決定採取第三個方法，以\n武力拘禁蔣委員長。」上述「政治主張」最可能為下列何者？", "options": ["立即停止內戰，聯合各黨派抗日 & 蔣委員長：此處指蔣中正。", "反對洪憲帝制，起兵討伐袁世凱", "終結軍閥混戰，完成中國的統一", "攘外必先安內，全力剿滅共產黨"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 20, "raw_text": "20. 「關於我的『政治主張』，因為和蔣委員長在意見上的衝突，已經沒有和解的\n    跡象。我考慮了三種方法來解決此事，第一是辭職、第二是勸諫、第三是兵\n    諫。第一個方法因為我的國難家仇，和東北軍部下們的反對而不可行。最近我\n    試了第二個方法，但導致蔣委員長極端憤怒。因此我決定採取第三個方法，以\n    武力拘禁蔣委員長。」上述「政治主張」最可能為下列何者？\n    (A)立即停止內戰，聯合各黨派抗日\n                          & 蔣委員長：此處指蔣中正。\n    (B)反對洪憲帝制，起兵討伐袁世凱\n    (C)終結軍閥混戰，完成中國的統一\n    (D)攘外必先安內，全力剿滅共產黨\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-021", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "雅加達自十七世紀以來一直是印尼的政治、經濟中心，不過由於人口過於集\n中加上大量開發，對環境已產生過多負荷。近年來，雅加達的民眾飽受交通\n壅塞、空氣汙染、地層下陷及水患之苦，因此印尼政府計畫將首都遷至婆羅\n洲。但有生態專家提出警告，該處是紅毛猩猩的棲息地，遷都計畫所需的開\n發過程必須謹慎評估，否則反而可能破壞環境，造成生態浩劫。上述討論內\n容與下列何項議題最相符？", "options": ["歷史古都的文化保存", "遷移首都的機會成本", "都市人口結構的變化", "群島國家國土的擴張"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 21, "raw_text": "21. 雅加達自十七世紀以來一直是印尼的政治、經濟中心，不過由於人口過於集\n    中加上大量開發，對環境已產生過多負荷。近年來，雅加達的民眾飽受交通\n    壅塞、空氣汙染、地層下陷及水患之苦，因此印尼政府計畫將首都遷至婆羅\n    洲。但有生態專家提出警告，該處是紅毛猩猩的棲息地，遷都計畫所需的開\n    發過程必須謹慎評估，否則反而可能破壞環境，造成生態浩劫。上述討論內\n    容與下列何項議題最相符？\n    (A)歷史古都的文化保存   (B)遷移首都的機會成本\n    (C)都市人口結構的變化   (D)群島國家國土的擴張\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-022", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "國際刑警組織共有195個成員國，總部建有一個存放上百萬名國際刑事罪犯檔\n案的資料庫供成員國使用。我國目前受限於一個中國原則，無法加入此國際\n組織，因此未能分享或接收該組織的情報資訊，所以難以確認入境我國的旅\n客在境外是否有犯罪紀錄，而從我國潛逃出境的犯罪者也較難被繩之以法。\n上述內容顯示一個中國原則對我國產生下列哪一影響？", "options": ["兩岸互信不足造成軍事衝突現象頻傳", "兩岸交流趨緩使得經濟貿易往來受阻", "資訊科技落差造成區域發展程度不均", "資訊傳達受限使得國內治安風險升高"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 22, "raw_text": "22. 國際刑警組織共有195個成員國，總部建有一個存放上百萬名國際刑事罪犯檔\n    案的資料庫供成員國使用。我國目前受限於一個中國原則，無法加入此國際\n    組織，因此未能分享或接收該組織的情報資訊，所以難以確認入境我國的旅\n    客在境外是否有犯罪紀錄，而從我國潛逃出境的犯罪者也較難被繩之以法。\n    上述內容顯示一個中國原則對我國產生下列哪一影響？\n    (A)兩岸互信不足造成軍事衝突現象頻傳\n    (B)兩岸交流趨緩使得經濟貿易往來受阻\n    (C)資訊科技落差造成區域發展程度不均\n    (D)資訊傳達受限使得國內治安風險升高\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-023", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "圖(九)呈現我國1998至2018年間，\n䱰岭㮟㭩\n悏噋㰵⓭\n\u0015\u0018\n收入最高20%家庭與收入最低20%            \u0015\u0013\n\u0014\u0018\nノ搵䉅\n家庭的可支配所得成長率變化，其              \u0014\u0013\n中灰階區塊是曾發生經濟成長率大               \u0018\n幅衰退的兩段時間。根據圖中內容            \b \u0013\n\u0010\u0018\n判斷，上述兩個灰階區塊的數據，             \u0010\u0014\u0013\n\u0010\u0014\u0018\n呈現出下列哪一現象？                   \u0014\n\u001b   \u0015\u0013\u0013\u0015 \u0015\u0013\u0013\u0019 \u0015\u0013\u0014\u0013 \u0015\u0013\u0014\u0017 \u0015\u0013\u0014\u001b ⴲ\n㏴‣㖾榖\u0015\u0013\b⩴⵫\n& 家庭可支配所得：家庭可以自由使用                       ㏴‣㖾Ḍ\u0015\u0013\b⩴⵫\n於消費或儲蓄的所得。                                圖(九)", "options": ["收入較高者的財富減損情況較嚴重", "收入較低者的生活面臨較嚴重衝擊", "經濟大幅衰退造成區域間發展不均", "經濟大幅衰退反而縮小了貧富差距"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 23, "raw_text": "23. 圖(九)呈現我國1998至2018年間，\n                                        䱰岭㮟㭩\n\n\n\n\n                                                  悏噋㰵⓭\n                                 \u0015\u0018\n    收入最高20%家庭與收入最低20%            \u0015\u0013\n                                 \u0014\u0018\n                               ノ搵䉅\n\n\n\n\n    家庭的可支配所得成長率變化，其              \u0014\u0013\n    中灰階區塊是曾發生經濟成長率大               \u0018\n    幅衰退的兩段時間。根據圖中內容            \